package com.load.api.service;

import java.util.Comparator;
import java.util.List;
import java.util.Objects;
import java.util.stream.Stream;

import org.springframework.stereotype.Service;
import org.springframework.web.client.RestClient;
import org.springframework.web.client.RestClientException;
import org.springframework.web.client.RestClientResponseException;

import com.load.api.dto.ProductApiItemDTO;
import com.load.api.dto.ProductApiResponseDTO;
import com.load.api.dto.ProductResultDTO;
import com.load.api.exception.CustomException;
import com.load.api.exception.ExternalApiException;

@Service
public class ProductService {

    private final RestClient restClient;

    public ProductService(RestClient.Builder restClientBuilder) {
        this.restClient = restClientBuilder
                .baseUrl("https://dummyjson.com")
                .build();
    }

    public List<ProductResultDTO> getTopAvailableProducts(String category, double minRating, int limit) {
        validateInputs(category, limit);

        ProductApiResponseDTO response = fetchProductsFromExternalApi();

        if (response == null || response.getProducts() == null || response.getProducts().isEmpty()) {
            return List.of();
        }

        Stream<ProductApiItemDTO> stream = response.getProducts()
                .stream()
                .filter(Objects::nonNull);

        stream = stream.filter(product ->
                product.getCategory() != null &&
                product.getCategory().equalsIgnoreCase(category)
        );

        stream = stream.filter(product -> product.getRating() >= minRating);

        stream = stream.filter(product -> product.getStock() > 0);

        return stream
                .sorted(
                        Comparator.comparing(ProductApiItemDTO::getRating).reversed()
                                .thenComparing(ProductApiItemDTO::getPrice)
                                .thenComparing(
                                        product -> product.getTitle() == null ? "" : product.getTitle(),
                                        String.CASE_INSENSITIVE_ORDER
                                )
                )
                .limit(limit)
                .map(this::mapToResultDTO)
                .toList();
    }

    private ProductApiResponseDTO fetchProductsFromExternalApi() {
        try {
            return restClient
                    .get()
                    .uri("/products")
                    .retrieve()
                    .body(ProductApiResponseDTO.class);
        } catch (RestClientResponseException ex) {
            throw new ExternalApiException(
                    "External API returned error. status=" + ex.getStatusCode(),
                    ex
            );
        } catch (RestClientException ex) {
            throw new ExternalApiException("External API request failed", ex);
        }
    }

    private void validateInputs(String category, int limit) {
        if (category == null || category.isBlank()) {
            throw new CustomException("category cannot be null or blank");
        }

        if (limit <= 0) {
            throw new CustomException("limit must be greater than 0");
        }
    }

    private ProductResultDTO mapToResultDTO(ProductApiItemDTO product) {
        return new ProductResultDTO(
                product.getId(),
                product.getTitle(),
                product.getCategory(),
                product.getBrand(),
                product.getPrice(),
                product.getRating(),
                product.getStock()
        );
    }
}


