ProductController.java

Burada asıl task için GET koyuyorum. Ayrıca senin istediğin gibi örnek olması için POST / PUT / DELETE de ekliyorum.

package com.load.api.controller;

import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;

import org.springframework.http.HttpStatus;
import org.springframework.validation.annotation.Validated;
import org.springframework.web.bind.annotation.*;

import com.load.api.dto.ProductMutationRequestDTO;
import com.load.api.dto.ProductResultDTO;
import com.load.api.service.ProductService;

import jakarta.validation.Valid;

@RestController
@RequestMapping("/api/products")
@Validated
public class ProductController {

    private final ProductService productService;

    public ProductController(ProductService productService) {
        this.productService = productService;
    }

    @GetMapping("/top")
    public List<ProductResultDTO> getTopAvailableProducts(
            @RequestParam String category,
            @RequestParam double minRating,
            @RequestParam int limit
    ) {
        return productService.getTopAvailableProducts(category, minRating, limit);
    }

    @PostMapping
    @ResponseStatus(HttpStatus.CREATED)
    public Map<String, Object> createProductExample(@Valid @RequestBody ProductMutationRequestDTO requestDTO) {
        Map<String, Object> response = new LinkedHashMap<>();
        response.put("message", "Example POST endpoint. No real external product creation is done.");
        response.put("receivedTitle", requestDTO.getTitle());
        response.put("receivedCategory", requestDTO.getCategory());
        return response;
    }

    @PutMapping("/{id}")
    public Map<String, Object> updateProductExample(
            @PathVariable Long id,
            @Valid @RequestBody ProductMutationRequestDTO requestDTO
    ) {
        Map<String, Object> response = new LinkedHashMap<>();
        response.put("message", "Example PUT endpoint. No real external product update is done.");
        response.put("productId", id);
        response.put("receivedTitle", requestDTO.getTitle());
        return response;
    }

    @DeleteMapping("/{id}")
    public Map<String, Object> deleteProductExample(@PathVariable Long id) {
        Map<String, Object> response = new LinkedHashMap<>();
        response.put("message", "Example DELETE endpoint. No real external product deletion is done.");
        response.put("productId", id);
        return response;
    }
}


